import{_ as t,o as a,c as i,ak as r}from"./chunks/framework.Bi-31Ycc.js";const u=JSON.parse('{"title":"Intellectual Property AND Collaboration Notice - Punjab Educare","description":"","frontmatter":{"title":"Intellectual Property AND Collaboration Notice - Punjab Educare","lastUpdated":false},"headers":[],"relativePath":"punjab-educare/intellectual-property-collaboration-notice.md","filePath":"punjab-educare/intellectual-property-collaboration-notice.md"}'),o={name:"punjab-educare/intellectual-property-collaboration-notice.md"};function n(l,e,s,c,d,p){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="intellectual-property-and-collaboration-notice" tabindex="-1">Intellectual Property AND Collaboration Notice <a class="header-anchor" href="#intellectual-property-and-collaboration-notice" aria-label="Permalink to “Intellectual Property AND Collaboration Notice”">​</a></h1><p>Effective Date: September 29, 2025</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>This webpage summarizes ownership, usage rights, and permitted commercial uses of Punjab Educare components for transparency; it is informational only, not a signed or executed contract, and does not request signatures or consent.</p></div><h2 id="parties" tabindex="-1">Parties <a class="header-anchor" href="#parties" aria-label="Permalink to “Parties”">​</a></h2><p>This Notice is presented as of <strong>September 29, 2025</strong>.</p><p>BY AND BETWEEN <strong>Jasamrit Singh Bhamra (BXAMRA)</strong>, hereinafter referred to as the “Developer/Owner,”</p><p>AND <strong>Punjab Educare Team</strong>, hereinafter referred to as the “Client.”</p><p>Collectively referred to as the “Parties.”</p><h2 id="_1-purpose-notice" tabindex="-1">1. Purpose &amp; Notice <a class="header-anchor" href="#_1-purpose-notice" aria-label="Permalink to “1. Purpose &amp; Notice”">​</a></h2><p>This page is intended to clearly communicate roles, ownership, and permitted use of the Punjab Educare end product components in a user-friendly format for public reference.</p><p>It is not a contract and has not been executed or signed by any Party; it serves as an informational ownership and collaboration notice only.</p><h2 id="_2-ownership-of-intellectual-property" tabindex="-1">2. Ownership of Intellectual Property <a class="header-anchor" href="#_2-ownership-of-intellectual-property" aria-label="Permalink to “2. Ownership of Intellectual Property”">​</a></h2><ul><li>The Developer is the sole owner of the mobile applications (Android &amp; iOS) source code and the Laravel backend/API, including architecture, features, builds, and related software assets.</li><li>The Client is the sole owner of the Punjab Educare website (domain, hosting, and content displayed on the website), which may be shown in the apps via WebView without transferring ownership.</li><li>Each Party agrees not to claim ownership of the other Party’s respective intellectual property.</li></ul><h2 id="_3-commercial-use-of-app-api-derivatives" tabindex="-1">3. Commercial Use of App/API Derivatives <a class="header-anchor" href="#_3-commercial-use-of-app-api-derivatives" aria-label="Permalink to “3. Commercial Use of App/API Derivatives”">​</a></h2><ul><li>The Developer reserves the right, at their sole discretion, to use, modify, or create derivative works based on the app and API code—including its structure, features, and architecture—and may commercially license, sell, distribute, or publish any resulting products under a different name, brand, subscription model, or other commercial arrangement, without restriction.</li></ul><h2 id="_4-database-data-vs-structure" tabindex="-1">4. Database: Data vs Structure <a class="header-anchor" href="#_4-database-data-vs-structure" aria-label="Permalink to “4. Database: Data vs Structure”">​</a></h2><ul><li>Database content (e.g., school data provided by the Department of Education, Punjab, and question bank content contributed by registered teachers) belongs to the Department of Education, Punjab and/or the respective contributors, as applicable.</li><li>The database structure/model/schema, including table designs, relationships, indices, and arrangement/selection of data elements, is owned by the Developer as part of the software and compilation design.</li><li>Access to data does not grant rights to copy, recreate, or reverse-engineer the database structure or app/API architecture, and repeated or substantial extraction of the structured compilation is not permitted.</li></ul><h2 id="_5-reciprocal-commercial-use-of-question-bank" tabindex="-1">5. Reciprocal Commercial Use of Question Bank <a class="header-anchor" href="#_5-reciprocal-commercial-use-of-question-bank" aria-label="Permalink to “5. Reciprocal Commercial Use of Question Bank”">​</a></h2><ul><li>In reciprocal acknowledgment of the free app development and services provided, the Developer is granted a non-exclusive, perpetual, worldwide license to use the question bank data contributed by registered teachers or provided by the Department of Education, Punjab.</li><li>The Developer may utilize the question bank data in whole or in part to build, develop, and launch other products, which may be sold commercially or offered under subscription-based models and under a different product name, brand, or platform, without geographical or time limitations.</li></ul><h2 id="_6-rights-of-use-access" tabindex="-1">6. Rights of Use &amp; Access <a class="header-anchor" href="#_6-rights-of-use-access" aria-label="Permalink to “6. Rights of Use &amp; Access”">​</a></h2><ul><li>The Department of Education, Punjab—including its teachers, students, and Department-affiliated schools (including privately managed institutions)—is granted a non-exclusive, royalty-free, worldwide, perpetual license to use the mobile apps and API for educational purposes, without limits on duration, seats, or usage.</li><li>Such license does not transfer ownership of the apps, codebase, API, database structure, or website to the Department or Client.</li><li>Display of the website via WebView is for convenience and does not transfer ownership of website assets to the Developer.</li></ul><h2 id="_7-hosting-publication" tabindex="-1">7. Hosting &amp; Publication <a class="header-anchor" href="#_7-hosting-publication" aria-label="Permalink to “7. Hosting &amp; Publication”">​</a></h2><ul><li>The Client may provide hosting services and may publish the Android app using their Google Play account as a technical convenience only; these actions do not grant ownership of the app or API.</li><li>The Developer may migrate hosting or publish under different developer accounts in the future as needed.</li></ul><h2 id="_8-department-of-education-interaction" tabindex="-1">8. Department of Education Interaction <a class="header-anchor" href="#_8-department-of-education-interaction" aria-label="Permalink to “8. Department of Education Interaction”">​</a></h2><ul><li>The Client may coordinate communications with the Department of Education, Punjab as an intermediary.</li><li>The Client shall not enter into any agreement on behalf of the Developer regarding the app, source code, or IP without the Developer’s prior written consent.</li><li>Any formal agreements concerning the app and its IP must be executed directly by the Developer.</li></ul><h2 id="_9-confidentiality" tabindex="-1">9. Confidentiality <a class="header-anchor" href="#_9-confidentiality" aria-label="Permalink to “9. Confidentiality”">​</a></h2><ul><li>Source code, backend/API credentials, and database administration access controlled by the Developer are confidential and not to be disclosed without prior written consent of the Developer.</li><li>Website domain/hosting credentials controlled by the Client are confidential and not to be disclosed without prior written consent of the Client.</li></ul><h2 id="_10-term-termination" tabindex="-1">10. Term &amp; Termination <a class="header-anchor" href="#_10-term-termination" aria-label="Permalink to “10. Term &amp; Termination”">​</a></h2><ul><li>This Notice remains in effect until superseded or replaced; if the Client withdraws, hosting and store-publication responsibilities may be transitioned by the Developer.</li><li>If the Developer withdraws, the Client retains ownership of the website but has no rights over the app or API.</li></ul><h2 id="_11-governing-law" tabindex="-1">11. Governing Law <a class="header-anchor" href="#_11-governing-law" aria-label="Permalink to “11. Governing Law”">​</a></h2><p>This Notice is intended to be interpreted in line with the laws of India in the event it is referenced in any formal agreement.</p>',31)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
